mapper.select:
SELECT COUNT(*)
FROM homeworkrecord hr
JOIN homework h ON hr.homework_id = h.id
WHERE hr.yonghu_id  = #{studentId}
  AND h.course_id   = #{courseId}
  AND hr.is_overdue = 1

SELECT COUNT(*)
FROM homework_alert
WHERE student_id = #{studentId}
  AND course_id  = #{courseId}
  AND is_read    = 0
